import { useState } from "react";

export default function CommentItem({
                                        comment,
                                        user,
                                        isAdmin,
                                        onDelete,
                                        toggleReaction,
                                        onReply,
                                        depth = 0
                                    }) {
    const [showReplies, setShowReplies] = useState(false);

    const canDelete =
        user &&
        (isAdmin || user.username === comment.username);

    const replyCount = comment.replies?.length || 0;

    return (
        <li
            className="comment-item"
            style={{ marginLeft: depth * 28 }}
        >
            {/* COMMENT BODY */}
            <div className="comment-box">
                <div className="comment-header">
                    <strong>{comment.username}</strong>
                    <span className="comment-time">
                        {new Date(comment.createdAt).toLocaleString()}
                    </span>
                </div>

                <div className="comment-text">
                    {comment.comment}
                </div>

                {/* ACTIONS */}
                <div className="comment-actions">
                    <button onClick={() => onReply(comment.id)}>
                        Reply
                    </button>

                    <button onClick={() => toggleReaction(comment, "LIKE")}>
                        👍 {comment.reactions?.counts?.LIKE || 0}
                    </button>

                    <button onClick={() => toggleReaction(comment, "DISLIKE")}>
                        👎 {comment.reactions?.counts?.DISLIKE || 0}
                    </button>

                    {canDelete && (
                        <button
                            className="danger"
                            onClick={() => onDelete(comment.id)}
                        >
                            Delete
                        </button>
                    )}
                </div>
            </div>

            {/* COLLAPSE / EXPAND TOGGLE */}
            {replyCount > 0 && (
                <button
                    className="toggle-replies"
                    onClick={() => setShowReplies(v => !v)}
                >
                    {showReplies
                        ? "Hide replies"
                        : `View ${replyCount} repl${replyCount > 1 ? "ies" : "y"}`}
                </button>
            )}

            {/* REPLIES */}
            {showReplies && (
                <ul className="reply-list">
                    {comment.replies.map(r => (
                        <CommentItem
                            key={r.id}
                            comment={r}
                            user={user}
                            isAdmin={isAdmin}
                            onDelete={onDelete}
                            toggleReaction={toggleReaction}
                            onReply={onReply}
                            depth={depth + 1}
                        />
                    ))}
                </ul>
            )}
        </li>
    );
}
